import crypto from "node:crypto";
import { pollLoginEvents } from "../agentSessionChannel.js";
import { reportHandoff } from "../analytics.js";
import { getConfig, hasCredentials, saveCredentials } from "../config.js";
import { recordFocus } from "../frontmostApp.js";
import { openStudioTo, StudioNavigationError } from "./openStudioTo.js";
const LOGIN_TIMEOUT_MS = 10 * 60 * 1000;
async function verifyToken(serviceUrl, token) {
    try {
        const res = await fetch(`${serviceUrl}/api/plugin/whoami`, {
            headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) {
            return null;
        }
        return (await res.json());
    }
    catch {
        return null;
    }
}
export async function runLogin(platform, pluginVersion, options) {
    const exitOnComplete = options?.exitOnComplete ?? true;
    const config = getConfig();
    const restoreFocus = recordFocus();
    const sessionId = crypto.randomUUID();
    const redirectPath = `/studio?pluginLogin=true&session=${sessionId}&autoClose=true`;
    const signInPath = `/studio/sign-in?redirect_url=${encodeURIComponent(redirectPath)}`;
    console.log("\nOpening Studio to sign in...");
    console.log("(If the browser didn't open, visit the Studio URL manually.)");
    // Open Studio to the sign-in page via the single entry point.
    // Pass apiKey if we have one (allows reusing an existing session),
    // null otherwise (opens browser directly).
    try {
        await openStudioTo(signInPath, {
            apiKey: hasCredentials() ? config.apiKey : null,
            serviceUrl: config.serviceUrl,
            sessionId,
        });
    }
    catch (err) {
        if (err instanceof StudioNavigationError) {
            await openStudioTo(signInPath, {
                apiKey: null,
                serviceUrl: config.serviceUrl,
                sessionId,
            });
        }
        else {
            throw err;
        }
    }
    // Poll for the authentication token (unauthenticated endpoint).
    const abortController = new AbortController();
    let loginTimer;
    const timeoutPromise = new Promise((_resolve, reject) => {
        loginTimer = setTimeout(() => {
            abortController.abort();
            reject(new Error("Authentication timed out after 10 minutes. Run login again."));
        }, LOGIN_TIMEOUT_MS);
    });
    const keepaliveTimer = setInterval(() => {
        process.stdout.write("");
    }, 30_000);
    try {
        const token = await Promise.race([
            pollLoginEvents({
                serviceUrl: config.serviceUrl,
                sessionId,
                abortSignal: abortController.signal,
            }),
            timeoutPromise,
        ]);
        if (loginTimer) {
            clearTimeout(loginTimer);
        }
        clearInterval(keepaliveTimer);
        saveCredentials(token);
        await reportHandoff(token, pluginVersion, platform, {
            flow: "auth.login",
            wonBy: "studio",
            loopbackAvailable: false,
            ticketAvailable: false,
        });
        restoreFocus();
        const who = await verifyToken(config.serviceUrl, token);
        const greeting = who?.user.email
            ? `Logged in as ${who.user.email}.`
            : "Authentication successful.";
        console.log(`\n${greeting}`);
        console.log("Bitfab MCP tools are now active. (via studio)");
        if (exitOnComplete) {
            process.exit(0);
        }
    }
    catch (err) {
        if (loginTimer) {
            clearTimeout(loginTimer);
        }
        clearInterval(keepaliveTimer);
        abortController.abort();
        if (exitOnComplete) {
            console.error(`\n${err.message}`);
            process.exit(1);
        }
        throw err;
    }
}
